import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { createServer } from 'node:http';
import type { IncomingMessage, ServerResponse } from 'node:http';
import queryRoute from './routes/query.ts';
import ingestRoute from './routes/ingest.ts';
import searchRoute from './routes/search.ts';

const app = new Hono();

app.use('*', cors());

app.get('/health', c => c.json({ status: 'ok', ts: Date.now() }));

app.route('/query', queryRoute);
app.route('/ingest', ingestRoute);
app.route('/doc', searchRoute);

const PORT = Number(process.env['PORT'] ?? 3000);

const server = createServer(async (req: IncomingMessage, res: ServerResponse) => {
  const url = new URL(req.url ?? '/', `http://localhost:${PORT}`);
  const headers: Record<string, string> = {};
  for (const [k, v] of Object.entries(req.headers)) {
    if (typeof v === 'string') headers[k] = v;
    else if (Array.isArray(v) && v[0]) headers[k] = v[0];
  }
  const res2 = await app.fetch(new Request(url.toString(), {
    method: req.method,
    headers,
    body: req.method !== 'GET' && req.method !== 'HEAD' ? req : undefined
  }));
  const outHeaders: Record<string, string> = {};
  res2.headers.forEach((v: string, k: string) => { outHeaders[k] = v; });
  res.writeHead(res2.status, outHeaders);
  res.end(await res2.text());
});

server.listen(PORT, () => {
  console.log(`RAG API listening on :${PORT}`);
});
